#!/usr/bin/env node
// build-creator-bundle.js — Concatenates creator/ files in dependency order
// Run: node build-creator-bundle.js
// Outputs: creator/bundle.js
//
// Phase 4: also auto-bumps CREATOR_CACHE_KEY in index.html based on the
// content hash of bundle.js + creator-main.js, so users automatically get
// fresh JS in their browsers without a manual version edit.
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

// Write `content` to `target` only if the existing file differs. Returns true
// when a write actually happened. Keeps the build idempotent so re-running
// `node build-creator-bundle.js` with no source changes leaves mtimes (and
// downstream watchers, IDE indexers, git status) untouched.
function writeIfChanged(target, content) {
  try {
    if (fs.existsSync(target)) {
      const current = fs.readFileSync(target, 'utf8');
      if (current === content) return false;
    }
  } catch (e) { /* fall through to write */ }
  fs.writeFileSync(target, content, 'utf8');
  return true;
}

// ── Bundle layout ──────────────────────────────────────────────────────────
// ORDER         → creator/bundle.js          (loaded eagerly on the Creator page)
// EXTRAS_ORDER  → creator/extras-bundle.js   (loaded with `defer` so it parses
//                                             after the main bundle without
//                                             blocking initial HTML parsing —
//                                             action plan §3.2)
//
// EXTRAS contains modules that are only needed for the Materials & Output
// page (LegendTab/PrepareTab/ExportTab/MaterialsHub and their helpers) plus
// the Stash-Adapt modal pipeline. Every consumer of these globals already
// guards with `typeof window.X !== 'undefined'` (or is itself in extras),
// so a slow extras-bundle never crashes the Pattern tab — the modal/tab
// just stays hidden until the script finishes parsing.
const ORDER = [
  'context.js',
  // Auto-save state machine — pure helper used by useProjectIO.js to drive
  // the visible save status badge in the header.
  'saveStatus.js',
  'symbolFontSpec.js',
  'generate.js',
  'canvasRenderer.js',
  'PreviewCanvas.js',
  'RealisticCanvas.js',
  'useMagicWand.js',
  'useLassoSelect.js',
  'useCreatorState.js',
  // useImportWizard.js + ImportWizard.js intentionally REMOVED from this
  // list — they are bundled into creator/import-wizard-bundle.js below and
  // loaded conditionally (only when experimental.importWizard pref is on).
  // Saves ~30 KB on every Creator page load for the default user.
  'useEditHistory.js',
  'useCanvasInteraction.js',
  'useKeyboardShortcuts.js',
  'useProjectIO.js',
  'usePreview.js',
  'PatternCanvas.js',
  'SplitPane.js',
  'ToolStrip.js',
  'MagicWandPanel.js',
  'BulkAddModal.js',
  'Sidebar.js',
  'Toast.js',
  'ContextMenu.js',
  'PatternTab.js',
  'ProjectTab.js',
  // UX-12 Phase 5: outcome action bar mounted in creator-main.js.
  // Option 2: PatternInfoPopover must load before ActionBar (which renders
  // it) so window.CreatorPatternInfoPopover is defined at mount time.
  'PatternInfoPopover.js',
  'ColourReplaceModal.js',
  'ActionBar.js',
];

// Materials & Output + Stash-Adapt — lazy-loaded via creator/extras-bundle.js.
// matchQuality.js MUST precede adaptationEngine.js, which MUST precede
// AdaptModal.js. ExportTab depends on DesignerBrandingSection. MaterialsHub
// renders LegendTab/PrepareTab/ExportTab so they all must be concatenated
// before it.
const EXTRAS_ORDER = [
  'matchQuality.js',
  'adaptationEngine.js',
  'pdfChartLayout.js',
  'pdfExport.js',
  'zipBundle.js',
  'AdaptModal.js',
  'LegendTab.js',
  'PrepareTab.js',
  'DesignerBrandingSection.js',
  'ExportTab.js',
  'ShoppingListModal.js',
  'MaterialsHub.js',
];

const parts = ORDER.map(name => {
  const src = fs.readFileSync(path.join('creator', name), 'utf8');
  return `/* ─── ${name} ─── */\n${src}`;
});

const banner = `/* creator/bundle.js — AUTO-GENERATED by build-creator-bundle.js
   Do not edit directly. Edit the source files in creator/ and re-run the build. */\n\n`;

const bundle = banner + parts.join('\n\n');
const bundleTarget = path.join('creator', 'bundle.js');
const bundleChanged = writeIfChanged(bundleTarget, bundle);

const kb = (bundle.length / 1024).toFixed(1);
console.log(`creator/bundle.js ${bundleChanged ? 'written' : 'unchanged'} \u2014 ${bundle.length} bytes (${kb} KB), ${ORDER.length} files merged`);

// ── Build the deferred extras bundle (action plan §3.2) ────────────────────
// Materials & Output components + Stash-Adapt modal pipeline. Loaded with
// `defer` from create.html so it downloads in parallel with the main bundle
// but doesn't block HTML parsing. Saves ~210 KB of synchronous parse cost
// on the critical path before first paint.
const extrasParts = EXTRAS_ORDER.map(name => {
  const src = fs.readFileSync(path.join('creator', name), 'utf8');
  return `/* \u2500\u2500\u2500 ${name} \u2500\u2500\u2500 */\n${src}`;
});
const extrasBanner = `/* creator/extras-bundle.js \u2014 AUTO-GENERATED by build-creator-bundle.js
   Lazy-loaded second bundle for Materials & Output components and the
   Stash-Adapt modal pipeline. Loaded with \`defer\` from create.html so it
   does not block initial HTML parsing. Do not edit directly. */\n\n`;
const extrasBundle = extrasBanner + extrasParts.join('\n\n');
const extrasTarget = path.join('creator', 'extras-bundle.js');
const extrasChanged = writeIfChanged(extrasTarget, extrasBundle);
const ekb = (extrasBundle.length / 1024).toFixed(1);
console.log(`creator/extras-bundle.js ${extrasChanged ? 'written' : 'unchanged'} \u2014 ${extrasBundle.length} bytes (${ekb} KB), ${EXTRAS_ORDER.length} files merged`);

// ── Build the conditional Import Wizard bundle ─────────────────────────────
// useImportWizard.js + ImportWizard.js are concatenated into a separate
// bundle that's loaded on demand when UserPrefs `experimental.importWizard`
// is on. This keeps the main creator bundle ~30 KB lighter for the default
// (flag off) user. See reports/perf-results-* for measured impact.
const WIZARD_ORDER = ['useImportWizard.js', 'ImportWizard.js'];
const wizardParts = WIZARD_ORDER.map(name => {
  const src = fs.readFileSync(path.join('creator', name), 'utf8');
  return `/* ─── ${name} ─── */\n${src}`;
});
const wizardBanner = `/* creator/import-wizard-bundle.js — AUTO-GENERATED by build-creator-bundle.js
   Conditionally loaded by tracker-app.js / creator-main.js when the
   experimental.importWizard preference is enabled. Do not edit directly. */\n\n`;
const wizardBundle = wizardBanner + wizardParts.join('\n\n');
const wizardTarget = path.join('creator', 'import-wizard-bundle.js');
const wizardChanged = writeIfChanged(wizardTarget, wizardBundle);
const wkb = (wizardBundle.length / 1024).toFixed(1);
console.log(`creator/import-wizard-bundle.js ${wizardChanged ? 'written' : 'unchanged'} \u2014 ${wizardBundle.length} bytes (${wkb} KB), ${WIZARD_ORDER.length} files merged`);

// Auto-bump CREATOR_CACHE_KEY in create.html and index.html so the
// in-browser babel cache for creator-main.js invalidates whenever the
// bundle, the extras-bundle, or creator-main.js change. (Action plan §3.2:
// extras-bundle now contributes to the hash so a Materials & Output edit
// also busts the compiled-app cache, and the same key is written to both
// HTML files so they stay in sync.)
try {
  const creatorMainPath = 'creator-main.js';
  if (fs.existsSync(creatorMainPath)) {
    const creatorMain = fs.readFileSync(creatorMainPath);
    const hash = crypto.createHash('sha256')
      .update(bundle)
      .update(extrasBundle)
      .update(creatorMain)
      .digest('hex')
      .slice(0, 10);
    const newKey = `babel_creator_${hash}`;
    const re = /var\s+CREATOR_CACHE_KEY\s*=\s*['"][^'"]+['"]/;
    for (const target of ['create.html', 'index.html']) {
      if (!fs.existsSync(target)) continue;
      const html = fs.readFileSync(target, 'utf8');
      if (!re.test(html)) {
        console.warn(`${target}: CREATOR_CACHE_KEY declaration not found — skipped auto-bump`);
        continue;
      }
      const updated = html.replace(re, `var CREATOR_CACHE_KEY = '${newKey}'`);
      if (updated !== html) {
        fs.writeFileSync(target, updated, 'utf8');
        console.log(`${target} CREATOR_CACHE_KEY → ${newKey}`);
      } else {
        console.log(`${target} CREATOR_CACHE_KEY unchanged (${newKey})`);
      }
    }
  }
} catch (e) {
  console.warn('Auto-bump of CREATOR_CACHE_KEY failed:', e.message);
}

// Auto-bump the other Babel-cache keys in index.html based on a hash of the
// source file each one caches. Without this, edits to tracker-app.js,
// stats-activity.js, stats-insights.js or stats-page.js are invisible to any
// browser that already has the previous compiled output in localStorage —
// which is the most common cause of "the deploy looks like it didn't take
// effect" reports. Mapping is { CACHE_KEY_NAME: [sourceFilesToHash], prefix }.
//
// Action plan §2A.5: the same cache-key rewrite now also runs against
// stitch.html (TRACKER_CACHE_KEY) and manager.html (MANAGER_CACHE_KEY) so
// the tracker / manager Babel-cache loaders introduced in those pages stay
// in sync with the source.
try {
  const HTML_TARGETS = [
    {
      path: 'index.html',
      keys: [
        { varName: 'TRACKER_CACHE_KEY',  prefix: 'babel_tracker_',  files: ['tracker-app.js'] },
        { varName: 'ACTIVITY_CACHE_KEY', prefix: 'babel_activity_', files: ['stats-activity.js'] },
        { varName: 'INSIGHTS_CACHE_KEY', prefix: 'babel_insights_', files: ['stats-insights.js'] },
        { varName: 'STATS_CACHE_KEY',    prefix: 'babel_stats_',    files: ['stats-page.js'] },
      ],
    },
    {
      path: 'stitch.html',
      keys: [
        { varName: 'TRACKER_CACHE_KEY',  prefix: 'babel_tracker_',  files: ['tracker-app.js'] },
      ],
    },
    {
      path: 'manager.html',
      keys: [
        { varName: 'MANAGER_CACHE_KEY',  prefix: 'babel_manager_',  files: ['manager-app.js'] },
      ],
    },
  ];
  for (const target of HTML_TARGETS) {
    if (!fs.existsSync(target.path)) continue;
    let html = fs.readFileSync(target.path, 'utf8');
    let changed = false;
    for (const entry of target.keys) {
      const missing = entry.files.filter(f => !fs.existsSync(f));
      if (missing.length) {
        console.warn(`Auto-bump skipped for ${entry.varName}: missing ${missing.join(', ')}`);
        continue;
      }
      const h = crypto.createHash('sha256');
      for (const f of entry.files) h.update(fs.readFileSync(f));
      const newKey = `${entry.prefix}${h.digest('hex').slice(0, 10)}`;
      const re = new RegExp(`var\\s+${entry.varName}\\s*=\\s*['"][^'"]+['"]`);
      if (!re.test(html)) {
        console.warn(`${target.path}: ${entry.varName} declaration not found — skipped`);
        continue;
      }
      const updated = html.replace(re, `var ${entry.varName} = '${newKey}'`);
      if (updated !== html) {
        html = updated;
        changed = true;
        console.log(`${target.path} ${entry.varName} → ${newKey}`);
      } else {
        console.log(`${target.path} ${entry.varName} unchanged (${newKey})`);
      }
    }
    if (changed) fs.writeFileSync(target.path, html, 'utf8');
  }
} catch (e) {
  console.warn('Auto-bump of secondary Babel cache keys failed:', e.message);
}
